class Solution(object):
    def findKthPositive(self, arr, k):
        missing = 0
        current = 1
        arr_idx = 0
        while missing < k:
            if arr_idx < len(arr) and arr[arr_idx] == current:
                arr_idx += 1
            else:
                missing += 1
                if missing == k:
                    return current
            current += 1
        return current - 1
